parameters.jsCode:
// ----------------------------
// INPUT DATA
// ----------------------------
const deal = $('Is Follow-up Due?').item.json.raw;
const ai = $json.output || {};

// ----------------------------
// SAFE DATE RESOLUTION
// ----------------------------
const lastActivityTime =
  deal.Last_Activity_Time ||
  deal.Last_Follow_up_At ||
  deal.Created_Time ||
  null;

let daysSinceLastActivity = null;

if (lastActivityTime) {
  const lastActivity = new Date(lastActivityTime);
  daysSinceLastActivity = Math.floor(
    (Date.now() - lastActivity.getTime()) / (1000 * 60 * 60 * 24)
  );
}

// ----------------------------
// FOLLOW-UP CHANNEL LOGIC
// ----------------------------
// Default from AI
let followUpType = ai.channel || "email";

// Hard override based on inactivity
if (daysSinceLastActivity !== null) {
  if (daysSinceLastActivity > 14) {
    followUpType = "call";
  } else if (daysSinceLastActivity > 7) {
    followUpType = "whatsapp";
  }
}

// ----------------------------
// FINAL OUTPUT
// ----------------------------
return {
  ...$json,

  followUpDecision: {
    lastActivityTime,
    followUpType,
    daysSinceLastActivity,
    aiSuggestedChannel: ai.channel || null,
    priority: ai.priority || "Normal",
    nextAction: ai.next_action || null,
  }
};

